#include <bits/stdc++.h>
using namespace std;int n,m;vector<int>cur;string o;
void bt(int start){if((int)cur.size()==m){for(int i=0;i<m;i++){o+=to_string(cur[i]);o+=(i+1<m?' ':'\n');}return;}for(int i=start;i<=n;i++){cur.push_back(i);bt(i+1);cur.pop_back();}}
int main(){cin>>n>>m;bt(1);cout<<o;}
